using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextHelper.CreateContext();
            _controller = new StudentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Student CreateStudent(string first = "John", string last = "Doe", DateTime? date = null)
        {
            return new Student
            {
                FirstMidName = first,
                LastName = last,
                EnrollmentDate = date ?? new DateTime(2020, 9, 1)
            };
        }

        private void SeedStudents(params Student[] students)
        {
            _context.Students.AddRange(students);
            _context.SaveChanges();
        }

        #region Index

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithStudentsOrderedByLastName()
        {
            SeedStudents(
                CreateStudent("B", "Zeta"),
                CreateStudent("A", "Alpha")
            );

            var result = _controller.Index(null, null, null, null) as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
            Assert.AreEqual("Alpha", model[0].LastName);
            Assert.AreEqual("Zeta", model[1].LastName);
        }

        [TestMethod]
        public void Index_NameDesc_SortsDescending()
        {
            SeedStudents(
                CreateStudent("A", "Alpha"),
                CreateStudent("B", "Beta")
            );

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual("Beta", model[0].LastName);
            Assert.AreEqual("Alpha", model[1].LastName);
        }

        [TestMethod]
        public void Index_DateSort_SortsByEnrollmentDateAscending()
        {
            SeedStudents(
                CreateStudent("B", "Late", new DateTime(2021, 1, 1)),
                CreateStudent("A", "Early", new DateTime(2019, 1, 1))
            );

            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual("Early", model[0].LastName);
            Assert.AreEqual("Late", model[1].LastName);
        }

        [TestMethod]
        public void Index_DateDescSort_SortsByEnrollmentDateDescending()
        {
            SeedStudents(
                CreateStudent("A", "Early", new DateTime(2019, 1, 1)),
                CreateStudent("B", "Late", new DateTime(2021, 1, 1))
            );

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual("Late", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchString_FiltersStudents()
        {
            SeedStudents(
                CreateStudent("John", "Smith"),
                CreateStudent("Jane", "Doe")
            );

            var result = _controller.Index(null, null, "Smith", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Smith", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchString_FiltersOnFirstName()
        {
            SeedStudents(
                CreateStudent("John", "Smith"),
                CreateStudent("Jane", "Doe")
            );

            var result = _controller.Index(null, null, "Jane", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Doe", model[0].LastName);
        }

        [TestMethod]
        public void Index_NullSearchWithCurrentFilter_UsesCurrentFilter()
        {
            SeedStudents(
                CreateStudent("John", "Smith"),
                CreateStudent("Jane", "Doe")
            );

            var result = _controller.Index(null, "Smith", null, 1) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.Count);
        }

        [TestMethod]
        public void Index_Pagination_ReturnsCorrectPage()
        {
            // Seed more than 10 students to test pagination
            for (int i = 0; i < 15; i++)
            {
                SeedStudents(CreateStudent($"Student{i}", $"Last{i:D2}"));
            }

            var result = _controller.Index(null, null, null, 2) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(5, model.Count);
            Assert.AreEqual(2, model.PageIndex);
        }

        [TestMethod]
        public void Index_NewSearch_ResetsToPage1()
        {
            SeedStudents(CreateStudent("John", "Smith"));

            var result = _controller.Index(null, null, "Smith", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.AreEqual(1, model.PageIndex);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var student = CreateStudent();
            SeedStudents(student);

            var result = _controller.Details(student.ID) as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.ID, model.ID);
        }

        #endregion

        #region Create GET

        [TestMethod]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [TestMethod]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = CreateStudent();

            var result = _controller.Create(student) as RedirectToActionResult;
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(1, _context.Students.Count());
        }

