        {
            var student = CreateStudent(date: DateTime.MinValue);

            var result = _controller.Create(student) as ViewResult;
            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = CreateStudent();

            var result = _controller.Create(student) as ViewResult;
            Assert.IsNotNull(result);
            Assert.AreEqual(0, _context.Students.Count());
        }

        #endregion

        #region Edit GET

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(999);
            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsView()
        {
            var student = CreateStudent();
            SeedStudents(student);

            var result = _controller.Edit((int?)student.ID) as ViewResult;
            Assert.IsNotNull(result);
            Assert.AreEqual(student.ID, ((Student)result.Model).ID);
        }

        #endregion

        #region Edit POST

        [TestMethod]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = CreateStudent();
            SeedStudents(student);
            // Detach to simulate form post
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            student.LastName = "Updated";
            var result = _controller.Edit(student) as RedirectToActionResult;
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_MinValueDate_ReturnsViewWithError()
        {
            var student = CreateStudent();
            SeedStudents(student);
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            student.EnrollmentDate = DateTime.MinValue;

            var result = _controller.Edit(student) as ViewResult;
            Assert.IsNotNull(result);
        }

        #endregion

        #region Delete GET

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
        }

        [TestMethod]
        public void Delete_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(999);
            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsView()
        {
