            SeedStudents(student);

            var result = _controller.DeleteConfirmed(student.ID) as RedirectToActionResult;
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(0, _context.Students.Count());
        }

        #endregion
    }
}

