+using System;
+using ContosoUniversity.Models;
+using ContosoUniversity.Services;
+using Microsoft.VisualStudio.TestTools.UnitTesting;
+
+namespace ContosoUniversity.Tests
+{
+    [TestClass]
+    public sealed class NotificationServiceTests
+    {
+        private NotificationService _sut;
+
+        [TestInitialize]
+        public void Setup()
+        {
+            _sut = new NotificationService();
+            // Drain the static queue to avoid interference between tests
+            while (_sut.ReceiveNotification() != null) { }
+        }
+
+        [TestCleanup]
+        public void Cleanup()
+        {
+            _sut.Dispose();
+        }
+
+        [TestMethod]
+        public void SendNotification_WithoutDisplayName_EnqueuesNotification()
+        {
+            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
+
+            var notification = _sut.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("Student", notification.EntityType);
+            Assert.AreEqual("1", notification.EntityId);
+            Assert.AreEqual("CREATE", notification.Operation);
+            Assert.IsFalse(notification.IsRead);
+            Assert.AreEqual("System", notification.CreatedBy);
+        }
+
+        [TestMethod]
+        public void SendNotification_WithDisplayName_EnqueuesNotification()
+        {
+            _sut.SendNotification("Student", "5", "John Doe", EntityOperation.CREATE, "Admin");
+
+            var notification = _sut.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("Student", notification.EntityType);
+            Assert.AreEqual("5", notification.EntityId);
+            Assert.AreEqual("Admin", notification.CreatedBy);
+            Assert.IsTrue(notification.Message.Contains("John Doe"));
+        }
+
+        [TestMethod]
+        public void SendNotification_WithUserName_SetsCreatedBy()
+        {
+            _sut.SendNotification("Course", "100", EntityOperation.UPDATE, "TestUser");
+
+            var notification = _sut.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("TestUser", notification.CreatedBy);
+        }
+
+        [TestMethod]
+        [DataRow(EntityOperation.CREATE, "New Student 'Alice' has been created", DisplayName = "CREATE message")]
+        [DataRow(EntityOperation.UPDATE, "Student 'Alice' has been updated", DisplayName = "UPDATE message")]
+        [DataRow(EntityOperation.DELETE, "Student 'Alice' has been deleted", DisplayName = "DELETE message")]
+        public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation op, string expectedMessage)
+        {
+            _sut.SendNotification("Student", "1", "Alice", op);
+
+            var notification = _sut.ReceiveNotification();
+            Assert.AreEqual(expectedMessage, notification.Message);
+        }
+
+        [TestMethod]
+        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
+        {
+            _sut.SendNotification("Course", "42", EntityOperation.CREATE);
+
+            var notification = _sut.ReceiveNotification();
+            Assert.AreEqual("New Course (ID: 42) has been created", notification.Message);
+        }
+
+        [TestMethod]
+        public void ReceiveNotification_EmptyQueue_ReturnsNull()
+        {
+            var notification = _sut.ReceiveNotification();
+            Assert.IsNull(notification);
+        }
+
+        [TestMethod]
+        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
+        {
+            _sut.SendNotification("A", "1", EntityOperation.CREATE);
+            _sut.SendNotification("B", "2", EntityOperation.UPDATE);
+            _sut.SendNotification("C", "3", EntityOperation.DELETE);
+
+            Assert.AreEqual("A", _sut.ReceiveNotification().EntityType);
+            Assert.AreEqual("B", _sut.ReceiveNotification().EntityType);
+            Assert.AreEqual("C", _sut.ReceiveNotification().EntityType);
+            Assert.IsNull(_sut.ReceiveNotification());
+        }
+
+        [TestMethod]
+        public void SendNotification_SetsCreatedAtToNow()
+        {
+            var before = DateTime.Now.AddSeconds(-1);
+            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
+            var after = DateTime.Now.AddSeconds(1);
+
+            var notification = _sut.ReceiveNotification();
+            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
+        }
+
+        [TestMethod]
+        public void MarkAsRead_DoesNotThrow()
+        {
+            // MarkAsRead is a no-op but should not throw
+            _sut.MarkAsRead(1);
+            _sut.MarkAsRead(999);
+        }
+
+        [TestMethod]
+        public void Dispose_DoesNotThrow()
+        {
+            var svc = new NotificationService();
+            svc.Dispose();
+            // Should be safe to call
+        }
+
+        [TestMethod]
+        public void SendNotification_NullUserName_DefaultsToSystem()
+        {
+            _sut.SendNotification("Test", "1", EntityOperation.CREATE, null);
+
+            var notification = _sut.ReceiveNotification();
+            Assert.AreEqual("System", notification.CreatedBy);
+        }
+    }
+}
+

